-- Materialized views (source + TO-target tables exist from 001).
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.account_activity_mv TO price_data.account_activity (`account` String, `block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `event_name` LowCardinality(String), `block_timestamp` DateTime, `is_module_transfer` UInt8) AS SELECT arrayJoin(arrayDistinct(extractAll(args_json, '"(0x[0-9a-f]{64})"'))) AS account, block_height, event_index, extrinsic_index, event_name, block_timestamp, toUInt8((event_name IN ('Balances.Transfer', 'Tokens.Transfer', 'Currencies.Transferred')) AND ((JSONExtractString(args_json, 'from') LIKE '0x6d6f646c%') OR (JSONExtractString(args_json, 'to') LIKE '0x6d6f646c%'))) AS is_module_transfer FROM price_data.raw_events;
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.account_activity_v3_mv TO price_data.account_activity_v3 (`account` String, `block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `event_name` LowCardinality(String), `block_timestamp` DateTime, `is_module_transfer` UInt8, `asset_id` UInt32, `amount` UInt256, `has_amount` UInt8) AS WITH multiIf(event_name IN ('XYK.SellExecuted', 'LBP.SellExecuted'), JSONExtractString(args_json, 'salePrice'), event_name IN ('XYK.BuyExecuted', 'LBP.BuyExecuted'), JSONExtractString(args_json, 'amount'), (event_name IN ('Router.Executed', 'Omnipool.SellExecuted', 'Omnipool.BuyExecuted', 'Stableswap.SellExecuted', 'Stableswap.BuyExecuted')), JSONExtractString(args_json, 'amountOut'), JSONHas(args_json, 'claimed'), JSONExtractString(args_json, 'claimed'), JSONHas(args_json, 'amount'), JSONExtractString(args_json, 'amount'), JSONHas(args_json, 'shares'), JSONExtractString(args_json, 'shares'), JSONHas(args_json, 'balance'), JSONExtractString(args_json, 'balance'), JSONHas(args_json, 'vote'), multiIf(JSONExtractString(JSONExtractRaw(args_json, 'vote'), '__kind') = 'Split', toString(toUInt256OrZero(JSONExtractString(JSONExtractRaw(args_json, 'vote'), 'aye')) + toUInt256OrZero(JSONExtractString(JSONExtractRaw(args_json, 'vote'), 'nay'))), JSONExtractString(JSONExtractRaw(args_json, 'vote'), '__kind') = 'SplitAbstain', toString((toUInt256OrZero(JSONExtractString(JSONExtractRaw(args_json, 'vote'), 'aye')) + toUInt256OrZero(JSONExtractString(JSONExtractRaw(args_json, 'vote'), 'nay'))) + toUInt256OrZero(JSONExtractString(JSONExtractRaw(args_json, 'vote'), 'abstain'))), JSONExtractString(JSONExtractRaw(args_json, 'vote'), 'balance')), '') AS raw_amount SELECT arrayJoin(arrayDistinct(extractAll(args_json, '"(0x[0-9a-f]{64})"'))) AS account, block_height, event_index, extrinsic_index, event_name, block_timestamp, toUInt8((event_name IN ('Balances.Transfer', 'Tokens.Transfer', 'Currencies.Transferred')) AND ((JSONExtractString(args_json, 'from') LIKE '0x6d6f646c%') OR (JSONExtractString(args_json, 'to') LIKE '0x6d6f646c%'))) AS is_module_transfer, toUInt32(greatest(0, multiIf((event_name IN ('Router.Executed', 'Omnipool.SellExecuted', 'Omnipool.BuyExecuted', 'Stableswap.SellExecuted', 'Stableswap.BuyExecuted', 'XYK.SellExecuted', 'XYK.BuyExecuted', 'LBP.SellExecuted', 'LBP.BuyExecuted')), JSONExtractInt(args_json, 'assetOut'), event_name = 'Balances.Transfer', 0, JSONHas(args_json, 'rewardCurrency'), JSONExtractInt(args_json, 'rewardCurrency'), JSONHas(args_json, 'currencyId'), JSONExtractInt(args_json, 'currencyId'), JSONHas(args_json, 'currency_id'), JSONExtractInt(args_json, 'currency_id'), JSONHas(args_json, 'assetId'), JSONExtractInt(args_json, 'assetId'), JSONHas(args_json, 'asset_id'), JSONExtractInt(args_json, 'asset_id'), JSONHas(args_json, 'poolId'), JSONExtractInt(args_json, 'poolId'), JSONHas(args_json, 'assetA'), JSONExtractInt(args_json, 'assetA'), 0))) AS asset_id, toUInt256OrZero(raw_amount) AS amount, toUInt8(raw_amount != '') AS has_amount FROM price_data.raw_events;
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.account_asset_latest_balances_mv TO price_data.account_asset_latest_balances (`account_id` String, `asset_id` String, `total_state` AggregateFunction(argMax, Nullable(String), UInt32), `free_state` AggregateFunction(argMax, Nullable(String), UInt32), `reserved_state` AggregateFunction(argMax, Nullable(String), UInt32), `last_block_state` AggregateFunction(max, UInt32)) AS SELECT account_id, asset_id, argMaxState(total, block_height) AS total_state, argMaxState(free, block_height) AS free_state, argMaxState(reserved, block_height) AS reserved_state, maxState(block_height) AS last_block_state FROM price_data.raw_balance_observations WHERE (account_id != '') AND (asset_id != '') GROUP BY account_id, asset_id;
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.account_asset_latest_nonzero_balances_mv TO price_data.account_asset_latest_nonzero_balances (`account_id` String, `asset_id` String, `total_state` AggregateFunction(argMax, Nullable(String), UInt32), `last_block_state` AggregateFunction(max, UInt32)) AS SELECT account_id, asset_id, argMaxState(total, block_height) AS total_state, maxState(block_height) AS last_block_state FROM price_data.raw_balance_observations WHERE (account_id != '') AND (asset_id != '') AND (total != '') AND (total != '0') GROUP BY account_id, asset_id;
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.account_balance_history_mv TO price_data.account_balance_history (`account_id` String, `asset_id` String, `asset_kind` LowCardinality(String), `block_height` UInt32, `block_timestamp` DateTime, `observation_id` String, `total` String, `ingested_at` DateTime) AS SELECT account_id, asset_id, asset_kind, block_height, block_timestamp, observation_id, ifNull(total, '') AS total, ingested_at FROM price_data.raw_balance_observations WHERE (account_id != '') AND (asset_id != '');
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.account_balance_hourly_mv TO price_data.account_balance_hourly (`account_id` String, `asset_id` String, `interval_start` DateTime, `balance_state` AggregateFunction(argMax, String, Tuple(UInt32, String, DateTime)), `block_state` AggregateFunction(argMax, UInt32, Tuple(UInt32, String, DateTime)), `first_block_state` AggregateFunction(min, UInt32), `last_block_state` AggregateFunction(max, UInt32), `first_timestamp_state` AggregateFunction(min, DateTime), `last_timestamp_state` AggregateFunction(max, DateTime)) AS WITH tuple(block_height, observation_id, ingested_at) AS version SELECT account_id, asset_id, toStartOfHour(block_timestamp) AS interval_start, argMaxState(ifNull(toString(toUInt256OrZero(total)), '0'), version) AS balance_state, argMaxState(block_height, version) AS block_state, minState(block_height) AS first_block_state, maxState(block_height) AS last_block_state, minState(block_timestamp) AS first_timestamp_state, maxState(block_timestamp) AS last_timestamp_state FROM price_data.raw_balance_observations WHERE (account_id != '') AND (asset_id != '') GROUP BY account_id, asset_id, interval_start;
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.account_balance_weekly_mv TO price_data.account_balance_weekly (`account_id` String, `asset_id` String, `week_start` Date, `balance_state` AggregateFunction(argMax, String, Tuple(UInt32, UInt32, String, DateTime)), `activity_state` AggregateFunction(uniq, Tuple(UInt32, Nullable(UInt32))), `last_block_state` AggregateFunction(max, UInt32)) AS SELECT account_id, asset_id, toMonday(block_timestamp) AS week_start, argMaxState(coalesce(total, '0'), tuple(block_height, ifNull(source_event_index, toUInt32(4294967295)), observation_id, ingested_at)) AS balance_state, uniqState(tuple(block_height, source_event_index)) AS activity_state, maxState(block_height) AS last_block_state FROM price_data.raw_balance_observations WHERE (account_id != '') AND (asset_id != '') GROUP BY account_id, asset_id, week_start;
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.account_money_market_activity_mv TO price_data.account_money_market_activity (`account_id` Nullable(String), `block_height` UInt32, `event_index` UInt32, `block_timestamp` DateTime, `event_name` LowCardinality(String), `asset_address` String, `pool_address` Nullable(String), `amount` Nullable(String), `liquidated_collateral_amount` String, `ingested_at` DateTime) AS SELECT account_id, block_height, event_index, block_timestamp, event_name, ifNull(asset_address, '') AS asset_address, pool_address, amount, JSONExtractString(decoded_args_json, 'liquidatedCollateralAmount') AS liquidated_collateral_amount, ingested_at FROM price_data.raw_money_market_events WHERE ifNull(account_id, '') != '';
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.account_swap_activity_queue_mv TO price_data.account_swap_activity_queue (`queued_at` DateTime64(3), `block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `block_timestamp` DateTime, `event_name` LowCardinality(String), `asset_in` UInt32, `asset_out` UInt32, `amount_in` String, `amount_out` String, `ingested_at` DateTime) AS SELECT now64(3) AS queued_at, block_height, event_index, toUInt32(extrinsic_index) AS extrinsic_index, block_timestamp, event_name, toUInt32(greatest(0, JSONExtractInt(args_json, 'assetIn'))) AS asset_in, toUInt32(greatest(0, JSONExtractInt(args_json, 'assetOut'))) AS asset_out, multiIf(event_name IN ('XYK.SellExecuted', 'LBP.SellExecuted'), JSONExtractString(args_json, 'amount'), event_name IN ('XYK.BuyExecuted', 'LBP.BuyExecuted'), JSONExtractString(args_json, 'buyPrice'), JSONExtractString(args_json, 'amountIn')) AS amount_in, multiIf(event_name IN ('XYK.SellExecuted', 'LBP.SellExecuted'), JSONExtractString(args_json, 'salePrice'), event_name IN ('XYK.BuyExecuted', 'LBP.BuyExecuted'), JSONExtractString(args_json, 'amount'), JSONExtractString(args_json, 'amountOut')) AS amount_out, ingested_at FROM price_data.raw_events WHERE (event_name IN ('Router.Executed', 'Router.RouteExecuted', 'Omnipool.SellExecuted', 'Omnipool.BuyExecuted', 'Stableswap.SellExecuted', 'Stableswap.BuyExecuted', 'XYK.SellExecuted', 'XYK.BuyExecuted', 'LBP.SellExecuted', 'LBP.BuyExecuted')) AND (extrinsic_index IS NOT NULL);
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.account_transfer_activity_mv TO price_data.account_transfer_activity (`account` String, `block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `block_timestamp` DateTime, `event_name` LowCardinality(String), `call_address` Nullable(String), `from_account` String, `to_account` String, `amount` String, `asset_id` UInt32) AS WITH JSONExtractString(args_json, 'from') AS from_account, JSONExtractString(args_json, 'to') AS to_account SELECT arrayJoin(arrayFilter(account -> (account != ''), arrayDistinct([from_account, to_account]))) AS account, block_height, event_index, extrinsic_index, block_timestamp, event_name, call_address, from_account, to_account, JSONExtractString(args_json, 'amount') AS amount, toUInt32(if(event_name = 'Balances.Transfer', 0, multiIf(JSONHas(args_json, 'currencyId'), JSONExtractInt(args_json, 'currencyId'), JSONHas(args_json, 'currency_id'), JSONExtractInt(args_json, 'currency_id'), JSONHas(args_json, 'assetId'), JSONExtractInt(args_json, 'assetId'), JSONHas(args_json, 'asset_id'), JSONExtractInt(args_json, 'asset_id'), 0))) AS asset_id FROM price_data.raw_events WHERE event_name IN ('Balances.Transfer', 'Tokens.Transfer', 'Currencies.Transferred');
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.activity_histogram_events_mv TO price_data.activity_histogram_events (`day` Date, `block_height` UInt32, `event_index` UInt32, `activity_index` UInt32, `event_name` LowCardinality(String), `asset_refs` Array(UInt32), `ingested_at` DateTime) AS SELECT toDate(block_timestamp) AS day, block_height, event_index, toUInt32(if((event_name IN ('Router.Executed', 'Omnipool.SellExecuted', 'Omnipool.BuyExecuted', 'Stableswap.SellExecuted', 'Stableswap.BuyExecuted', 'XYK.SellExecuted', 'XYK.BuyExecuted', 'LBP.SellExecuted', 'LBP.BuyExecuted')), ifNull(extrinsic_index, event_index), event_index)) AS activity_index, event_name, multiIf((event_name IN ('Balances.Transfer', 'Tokens.Transfer', 'Currencies.Transferred')), [toUInt32(if(event_name = 'Balances.Transfer', 0, multiIf(JSONHas(args_json, 'currencyId'), greatest(0, JSONExtractInt(args_json, 'currencyId')), JSONHas(args_json, 'currency_id'), greatest(0, JSONExtractInt(args_json, 'currency_id')), JSONHas(args_json, 'assetId'), greatest(0, JSONExtractInt(args_json, 'assetId')), JSONHas(args_json, 'asset_id'), greatest(0, JSONExtractInt(args_json, 'asset_id')), 0)))], (event_name IN ('Router.Executed', 'Omnipool.SellExecuted', 'Omnipool.BuyExecuted', 'Stableswap.SellExecuted', 'Stableswap.BuyExecuted', 'XYK.SellExecuted', 'XYK.BuyExecuted', 'LBP.SellExecuted', 'LBP.BuyExecuted')), arrayDistinct([toUInt32(greatest(0, JSONExtractInt(args_json, 'assetIn'))), toUInt32(greatest(0, JSONExtractInt(args_json, 'assetOut')))]), (event_name IN ('Omnipool.LiquidityAdded', 'Omnipool.LiquidityRemoved', 'Stableswap.LiquidityAdded', 'Stableswap.LiquidityRemoved', 'XYK.LiquidityAdded', 'XYK.LiquidityRemoved', 'XYK.PoolCreated', 'OmnipoolLiquidityMining.RewardClaimed', 'XYKLiquidityMining.RewardClaimed')), arrayDistinct(arrayConcat(if(JSONHas(args_json, 'rewardCurrency'), [toUInt32(greatest(0, JSONExtractInt(args_json, 'rewardCurrency')))], CAST([], 'Array(UInt32)')), if(JSONHas(args_json, 'assetId'), [toUInt32(greatest(0, JSONExtractInt(args_json, 'assetId')))], CAST([], 'Array(UInt32)')), if(JSONHas(args_json, 'asset_id'), [toUInt32(greatest(0, JSONExtractInt(args_json, 'asset_id')))], CAST([], 'Array(UInt32)')), if(JSONHas(args_json, 'poolId'), [toUInt32(greatest(0, JSONExtractInt(args_json, 'poolId')))], CAST([], 'Array(UInt32)')), if(JSONHas(args_json, 'assetA'), [toUInt32(greatest(0, JSONExtractInt(args_json, 'assetA')))], CAST([], 'Array(UInt32)')), if(JSONHas(args_json, 'assetB'), [toUInt32(greatest(0, JSONExtractInt(args_json, 'assetB')))], CAST([], 'Array(UInt32)')), arrayMap(item -> toUInt32(greatest(0, JSONExtractInt(item, 'assetId'))), JSONExtractArrayRaw(args_json, 'assets')))), (event_name IN ('ConvictionVoting.Voted', 'Democracy.Voted', 'Referrals.Claimed')), [toUInt32(0)], (event_name IN ('CollatorRewards.CollatorRewarded', 'GigaHdx.Staked', 'GigaHdx.Unstaked', 'GigaHdx.UnstakeCancelled', 'GigaHdx.MigratedFromLegacy', 'GigaHdxRewards.RewardsClaimed', 'Staking.PositionCreated', 'Staking.StakeAdded', 'Staking.Unstaked', 'Staking.ForceUnstaked', 'Staking.RewardsClaimed')), [toUInt32(0), toUInt32(670)], event_name = 'OTC.Placed', arrayDistinct([toUInt32(greatest(0, JSONExtractInt(args_json, 'assetIn'))), toUInt32(greatest(0, JSONExtractInt(args_json, 'assetOut')))]), CAST([], 'Array(UInt32)')) AS asset_refs, ingested_at FROM price_data.raw_events WHERE event_name IN ('Router.Executed', 'Omnipool.SellExecuted', 'Omnipool.BuyExecuted', 'Stableswap.SellExecuted', 'Stableswap.BuyExecuted', 'XYK.SellExecuted', 'XYK.BuyExecuted', 'LBP.SellExecuted', 'LBP.BuyExecuted', 'OTC.Placed', 'OTC.Cancelled', 'OTC.Filled', 'OTC.PartiallyFilled', 'Omnipool.LiquidityAdded', 'Omnipool.LiquidityRemoved', 'Stableswap.LiquidityAdded', 'Stableswap.LiquidityRemoved', 'XYK.LiquidityAdded', 'XYK.LiquidityRemoved', 'XYK.PoolCreated', 'OmnipoolLiquidityMining.RewardClaimed', 'XYKLiquidityMining.RewardClaimed', 'Balances.Transfer', 'Tokens.Transfer', 'Currencies.Transferred', 'ConvictionVoting.Voted', 'Democracy.Voted', 'CollatorRewards.CollatorRewarded', 'GigaHdx.Staked', 'GigaHdx.Unstaked', 'GigaHdx.UnstakeCancelled', 'GigaHdx.MigratedFromLegacy', 'GigaHdxRewards.RewardsClaimed', 'Staking.PositionCreated', 'Staking.StakeAdded', 'Staking.Unstaked', 'Staking.ForceUnstaked', 'Staking.RewardsClaimed', 'DCA.TradeExecuted', 'DCA.TradeFailed', 'Referrals.Claimed');
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.asset_swap_activity_mv TO price_data.asset_swap_activity (`asset_id` UInt32, `block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `block_timestamp` DateTime, `event_name` LowCardinality(String), `who` String, `asset_in` UInt32, `asset_out` UInt32, `amount_in` String, `amount_out` String) AS SELECT arrayJoin(arrayDistinct([toUInt32(greatest(0, JSONExtractInt(args_json, 'assetIn'))), toUInt32(greatest(0, JSONExtractInt(args_json, 'assetOut')))])) AS asset_id, block_height, event_index, extrinsic_index, block_timestamp, event_name, JSONExtractString(args_json, 'who') AS who, toUInt32(greatest(0, JSONExtractInt(args_json, 'assetIn'))) AS asset_in, toUInt32(greatest(0, JSONExtractInt(args_json, 'assetOut'))) AS asset_out, multiIf(event_name IN ('XYK.SellExecuted', 'LBP.SellExecuted'), JSONExtractString(args_json, 'amount'), event_name IN ('XYK.BuyExecuted', 'LBP.BuyExecuted'), JSONExtractString(args_json, 'buyPrice'), JSONExtractString(args_json, 'amountIn')) AS amount_in, multiIf(event_name IN ('XYK.SellExecuted', 'LBP.SellExecuted'), JSONExtractString(args_json, 'salePrice'), event_name IN ('XYK.BuyExecuted', 'LBP.BuyExecuted'), JSONExtractString(args_json, 'amount'), JSONExtractString(args_json, 'amountOut')) AS amount_out FROM price_data.raw_events WHERE event_name IN ('Router.Executed', 'Router.RouteExecuted', 'Omnipool.SellExecuted', 'Omnipool.BuyExecuted', 'Stableswap.SellExecuted', 'Stableswap.BuyExecuted', 'XYK.SellExecuted', 'XYK.BuyExecuted', 'LBP.SellExecuted', 'LBP.BuyExecuted');
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.atoken_scaled_deltas_by_contract_mv TO price_data.atoken_scaled_deltas_by_contract (`contract_address` String, `holder` String, `block_height` UInt32, `event_index` UInt32, `block_timestamp` DateTime, `event_name` String, `leg_index` UInt8, `scaled_delta` Int256, `ingested_at` DateTime) AS WITH decoded_args_json AS ar, [if(event_name = 'Mint', JSONExtractString(ar, 'onBehalfOf'), if(event_name = 'Burn', JSONExtractString(ar, 'from'), JSONExtractString(ar, 'to'))), if(event_name = 'BalanceTransfer', JSONExtractString(ar, 'from'), '')] AS holders, [multiIf(event_name = 'Mint', intDiv((toInt256(toUInt256OrZero(JSONExtractString(ar, 'value'))) - toInt256(toUInt256OrZero(JSONExtractString(ar, 'balanceIncrease')))) * toInt256(toUInt256('1000000000000000000000000000')), greatest(toInt256(toUInt256OrZero(JSONExtractString(ar, 'index'))), toInt256(1))), event_name = 'Burn', -intDiv((toInt256(toUInt256OrZero(JSONExtractString(ar, 'value'))) + toInt256(toUInt256OrZero(JSONExtractString(ar, 'balanceIncrease')))) * toInt256(toUInt256('1000000000000000000000000000')), greatest(toInt256(toUInt256OrZero(JSONExtractString(ar, 'index'))), toInt256(1))), toInt256(toUInt256OrZero(JSONExtractString(ar, 'value')))), if(event_name = 'BalanceTransfer', -toInt256(toUInt256OrZero(JSONExtractString(ar, 'value'))), toInt256(0))] AS deltas, arrayJoin(arrayZip(holders, deltas, arrayEnumerate(holders))) AS leg SELECT lower(contract_address) AS contract_address, lower(tupleElement(leg, 1)) AS holder, block_height, event_index, block_timestamp, ifNull(event_name, '') AS event_name, toUInt8(tupleElement(leg, 3)) AS leg_index, tupleElement(leg, 2) AS scaled_delta, ingested_at FROM price_data.raw_evm_logs WHERE (event_name IN ('Mint', 'Burn', 'BalanceTransfer')) AND (tupleElement(leg, 1) != '');
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.atoken_scaled_deltas_mv TO price_data.atoken_scaled_deltas (`contract_address` String, `holder` String, `block_height` UInt32, `event_index` UInt32, `block_timestamp` DateTime, `event_name` String, `leg_index` UInt8, `scaled_delta` Int256, `ingested_at` DateTime) AS WITH decoded_args_json AS ar, [if(event_name = 'Mint', JSONExtractString(ar, 'onBehalfOf'), if(event_name = 'Burn', JSONExtractString(ar, 'from'), JSONExtractString(ar, 'to'))), if(event_name = 'BalanceTransfer', JSONExtractString(ar, 'from'), '')] AS holders, [multiIf(event_name = 'Mint', intDiv((toInt256(toUInt256OrZero(JSONExtractString(ar, 'value'))) - toInt256(toUInt256OrZero(JSONExtractString(ar, 'balanceIncrease')))) * toInt256(toUInt256('1000000000000000000000000000')), greatest(toInt256(toUInt256OrZero(JSONExtractString(ar, 'index'))), toInt256(1))), event_name = 'Burn', -intDiv((toInt256(toUInt256OrZero(JSONExtractString(ar, 'value'))) + toInt256(toUInt256OrZero(JSONExtractString(ar, 'balanceIncrease')))) * toInt256(toUInt256('1000000000000000000000000000')), greatest(toInt256(toUInt256OrZero(JSONExtractString(ar, 'index'))), toInt256(1))), toInt256(toUInt256OrZero(JSONExtractString(ar, 'value')))), if(event_name = 'BalanceTransfer', -toInt256(toUInt256OrZero(JSONExtractString(ar, 'value'))), toInt256(0))] AS deltas, arrayJoin(arrayZip(holders, deltas, arrayEnumerate(holders))) AS leg SELECT lower(contract_address) AS contract_address, lower(tupleElement(leg, 1)) AS holder, block_height, event_index, block_timestamp, ifNull(event_name, '') AS event_name, toUInt8(tupleElement(leg, 3)) AS leg_index, tupleElement(leg, 2) AS scaled_delta, ingested_at FROM price_data.raw_evm_logs WHERE (event_name IN ('Mint', 'Burn', 'BalanceTransfer')) AND (tupleElement(leg, 1) != '');
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.daily_event_identity_counts_v2_mv TO price_data.daily_chain_identity_counts_v2 (`kind` String, `day` Date, `identity_state` AggregateFunction(groupBitmap, UInt64)) AS SELECT 'events' AS kind, toDate(block_timestamp) AS day, groupBitmapState(bitOr(bitShiftLeft(toUInt64(event_index), 32), toUInt64(block_height))) AS identity_state FROM price_data.raw_events GROUP BY day;
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.daily_extrinsic_identity_counts_v2_mv TO price_data.daily_chain_identity_counts_v2 (`kind` String, `day` Date, `identity_state` AggregateFunction(groupBitmap, UInt64)) AS SELECT 'extrinsics' AS kind, toDate(block_timestamp) AS day, groupBitmapState(bitOr(bitShiftLeft(toUInt64(extrinsic_index), 32), toUInt64(block_height))) AS identity_state FROM price_data.raw_extrinsics WHERE coalesce(signer, effective_signer) IS NOT NULL GROUP BY day;
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.dca_events_mv TO price_data.dca_events (`id` UInt64, `event_name` LowCardinality(String), `block_height` UInt32, `block_timestamp` DateTime, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `who` String, `amount_in` String, `amount_out` String, `planned_block` UInt32) AS SELECT toUInt64(JSONExtractInt(args_json, 'id')) AS id, event_name, block_height, block_timestamp, event_index, extrinsic_index, JSONExtractString(args_json, 'who') AS who, JSONExtractString(args_json, 'amountIn') AS amount_in, JSONExtractString(args_json, 'amountOut') AS amount_out, toUInt32(JSONExtractInt(args_json, 'block')) AS planned_block FROM price_data.raw_events WHERE (event_name IN ('DCA.TradeExecuted', 'DCA.Completed', 'DCA.Terminated', 'DCA.ExecutionPlanned')) AND (JSONHas(args_json, 'id'));
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.dca_failed_events_mv TO price_data.dca_events (`id` UInt64, `event_name` LowCardinality(String), `block_height` UInt32, `block_timestamp` DateTime, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `who` String, `amount_in` String, `amount_out` String, `planned_block` UInt32) AS SELECT toUInt64(JSONExtractInt(args_json, 'id')) AS id, event_name, block_height, block_timestamp, event_index, extrinsic_index, JSONExtractString(args_json, 'who') AS who, '' AS amount_in, '' AS amount_out, toUInt32(0) AS planned_block FROM price_data.raw_events WHERE (event_name = 'DCA.TradeFailed') AND (JSONHas(args_json, 'id'));
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.dca_schedules_mv TO price_data.dca_schedules (`id` UInt64, `block_height` UInt32, `block_timestamp` DateTime, `extrinsic_index` Nullable(UInt32), `who` String, `asset_in` UInt32, `asset_out` UInt32, `direction` String, `amount_per` String, `total_amount` String, `period` UInt32, `max_retries` UInt32) AS SELECT toUInt64(JSONExtractInt(args_json, 'id')) AS id, block_height, block_timestamp, extrinsic_index, JSONExtractString(args_json, 'who') AS who, toUInt32(JSONExtractInt(args_json, 'order', 'assetIn')) AS asset_in, toUInt32(JSONExtractInt(args_json, 'order', 'assetOut')) AS asset_out, JSONExtractString(args_json, 'order', '__kind') AS direction, if(JSONHas(args_json, 'order', 'amountIn'), JSONExtractString(args_json, 'order', 'amountIn'), JSONExtractString(args_json, 'order', 'amountOut')) AS amount_per, JSONExtractString(args_json, 'totalAmount') AS total_amount, toUInt32(JSONExtractInt(args_json, 'period')) AS period, toUInt32(JSONExtractInt(args_json, 'maxRetries')) AS max_retries FROM price_data.raw_events WHERE (event_name = 'DCA.Scheduled') AND (JSONHas(args_json, 'id'));
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.erc20_transfer_deltas_mv TO price_data.erc20_transfer_deltas (`contract_address` String, `holder` String, `block_height` UInt32, `event_index` UInt32, `block_timestamp` DateTime, `leg_index` UInt8, `balance_delta` Int256, `ingested_at` DateTime) AS WITH decoded_args_json AS ar, [lower(JSONExtractString(ar, 'to')), lower(JSONExtractString(ar, 'from'))] AS holders, [toInt256OrZero(JSONExtractString(ar, 'value')), -toInt256OrZero(JSONExtractString(ar, 'value'))] AS deltas, arrayJoin(arrayZip(holders, deltas, arrayEnumerate(holders))) AS leg SELECT lower(contract_address) AS contract_address, tupleElement(leg, 1) AS holder, block_height, event_index, block_timestamp, toUInt8(tupleElement(leg, 3)) AS leg_index, tupleElement(leg, 2) AS balance_delta, ingested_at FROM price_data.raw_evm_logs WHERE (contract_address = '0x531a654d1696ed52e7275a8cede955e82620f99a') AND (event_name = 'Transfer') AND (tupleElement(leg, 1) != '');
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.event_asset_refs_mv TO price_data.event_asset_refs (`asset_id` UInt32, `event_name` LowCardinality(String), `block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `block_timestamp` DateTime, `ingested_at` DateTime) AS SELECT arrayJoin(arrayDistinct(arrayConcat(if(event_name = 'Balances.Transfer', [toUInt32(0)], emptyArrayUInt32()), if(JSONHas(args_json, 'currencyId'), [toUInt32(greatest(0, JSONExtractInt(args_json, 'currencyId')))], emptyArrayUInt32()), if(JSONHas(args_json, 'currency_id'), [toUInt32(greatest(0, JSONExtractInt(args_json, 'currency_id')))], emptyArrayUInt32()), if(JSONHas(args_json, 'assetId'), [toUInt32(greatest(0, JSONExtractInt(args_json, 'assetId')))], emptyArrayUInt32()), if(JSONHas(args_json, 'asset_id'), [toUInt32(greatest(0, JSONExtractInt(args_json, 'asset_id')))], emptyArrayUInt32()), if(JSONHas(args_json, 'assetIn'), [toUInt32(greatest(0, JSONExtractInt(args_json, 'assetIn')))], emptyArrayUInt32()), if(JSONHas(args_json, 'assetOut'), [toUInt32(greatest(0, JSONExtractInt(args_json, 'assetOut')))], emptyArrayUInt32()), if(JSONHas(args_json, 'assetA'), [toUInt32(greatest(0, JSONExtractInt(args_json, 'assetA')))], emptyArrayUInt32()), if(JSONHas(args_json, 'assetB'), [toUInt32(greatest(0, JSONExtractInt(args_json, 'assetB')))], emptyArrayUInt32()), if(JSONHas(args_json, 'poolId'), [toUInt32(greatest(0, JSONExtractInt(args_json, 'poolId')))], emptyArrayUInt32()), if(JSONHas(args_json, 'rewardCurrency'), [toUInt32(greatest(0, JSONExtractInt(args_json, 'rewardCurrency')))], emptyArrayUInt32()), if(JSONHas(args_json, 'currency'), [toUInt32(greatest(0, JSONExtractInt(args_json, 'currency')))], emptyArrayUInt32()), arrayMap(item -> toUInt32(greatest(0, JSONExtractInt(item, 'assetId'))), JSONExtractArrayRaw(args_json, 'assets'))))) AS asset_id, event_name, block_height, event_index, extrinsic_index, block_timestamp, ingested_at FROM price_data.raw_events;
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.farm_deposit_latest_mv TO price_data.farm_deposit_latest (`deposit_id` String, `position_id` AggregateFunction(argMax, String, UInt64)) AS SELECT JSONExtractString(args_json, 'depositId') AS deposit_id, argMaxState(JSONExtractString(args_json, 'positionId'), (toUInt64(block_height) * 4294967296) + event_index) AS position_id FROM price_data.raw_events WHERE (event_name IN ('OmnipoolLiquidityMining.SharesDeposited', 'OmnipoolLiquidityMining.SharesRedeposited')) AND (JSONExtractString(args_json, 'positionId') != '') GROUP BY deposit_id;
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.hdx_holder_lifetime_mv TO price_data.hdx_holder_lifetime (`account_id` String, `first_nonzero_state` AggregateFunction(min, DateTime), `last_nonzero_state` AggregateFunction(max, DateTime)) AS SELECT account_id, minState(block_timestamp) AS first_nonzero_state, maxState(block_timestamp) AS last_nonzero_state FROM price_data.raw_balance_observations WHERE (asset_id = '0') AND (account_id != '') AND (toUInt256OrZero(total) > 0) GROUP BY account_id;
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.hsm_activity_mv TO price_data.hsm_activity (`block_height` UInt32, `event_index` UInt32, `block_timestamp` DateTime, `event_name` LowCardinality(String), `args_json` String, `ingested_at` DateTime) AS SELECT block_height, event_index, block_timestamp, event_name, args_json, ingested_at FROM price_data.raw_events WHERE (event_name IN ('HSM.CollateralAdded', 'HSM.CollateralUpdated', 'HSM.ArbitrageExecuted')) OR ((event_name = 'Broadcast.Swapped3') AND (JSONExtractString(args_json, 'fillerType', '__kind') = 'HSM'));
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.incentive_claim_calls_mv TO price_data.incentive_claim_calls (`block_height` UInt32, `extrinsic_index` Nullable(UInt32), `call_address` String, `block_timestamp` DateTime, `ingested_at` DateTime) AS SELECT block_height, extrinsic_index, call_address, block_timestamp, ingested_at FROM price_data.raw_calls WHERE (position(args_json, '7472a3d0891df2401d981a5954d07e364f05060f') > 0) AND ((position(args_json, 'bb492bf5') > 0) OR (position(args_json, '236300dc') > 0));
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.incentive_reward_transfers_mv TO price_data.incentive_reward_transfers (`block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `block_timestamp` DateTime, `event_name` LowCardinality(String), `call_address` Nullable(String), `args_json` String, `ingested_at` DateTime) AS SELECT block_height, event_index, extrinsic_index, block_timestamp, event_name, call_address, args_json, ingested_at FROM price_data.raw_events WHERE (event_name IN ('Balances.Transfer', 'Tokens.Transfer', 'Currencies.Transferred')) AND (JSONExtractString(args_json, 'from') = '0x45544800112c208b900bcfc9ff8131d0f45769cb6c7c7d8d0000000000000000');
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.liquidity_activity_mv TO price_data.liquidity_activity (`block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `block_timestamp` DateTime, `event_name` LowCardinality(String), `who` String, `asset_id` UInt32, `amount` String, `amount_a` String, `asset_b` UInt32, `pool_account` String, `asset_refs` Array(UInt32), `ingested_at` DateTime) AS SELECT block_height, event_index, extrinsic_index, block_timestamp, event_name, JSONExtractString(args_json, 'who') AS who, toUInt32(greatest(0, multiIf(JSONHas(args_json, 'rewardCurrency'), JSONExtractInt(args_json, 'rewardCurrency'), JSONHas(args_json, 'assetId'), JSONExtractInt(args_json, 'assetId'), JSONHas(args_json, 'poolId'), JSONExtractInt(args_json, 'poolId'), JSONHas(args_json, 'assetA'), JSONExtractInt(args_json, 'assetA'), JSONExtractInt(args_json, 'asset_id')))) AS asset_id, multiIf(JSONHas(args_json, 'claimed'), JSONExtractString(args_json, 'claimed'), JSONHas(args_json, 'amount'), JSONExtractString(args_json, 'amount'), JSONExtractString(args_json, 'shares')) AS amount, JSONExtractString(args_json, 'amountA') AS amount_a, toUInt32(greatest(0, JSONExtractInt(args_json, 'assetB'))) AS asset_b, JSONExtractString(args_json, 'pool') AS pool_account, arrayDistinct(arrayConcat(if(JSONHas(args_json, 'rewardCurrency'), [toUInt32(greatest(0, JSONExtractInt(args_json, 'rewardCurrency')))], CAST([], 'Array(UInt32)')), if(JSONHas(args_json, 'assetId'), [toUInt32(greatest(0, JSONExtractInt(args_json, 'assetId')))], CAST([], 'Array(UInt32)')), if(JSONHas(args_json, 'asset_id'), [toUInt32(greatest(0, JSONExtractInt(args_json, 'asset_id')))], CAST([], 'Array(UInt32)')), if(JSONHas(args_json, 'poolId'), [toUInt32(greatest(0, JSONExtractInt(args_json, 'poolId')))], CAST([], 'Array(UInt32)')), if(JSONHas(args_json, 'assetA'), [toUInt32(greatest(0, JSONExtractInt(args_json, 'assetA')))], CAST([], 'Array(UInt32)')), if(JSONHas(args_json, 'assetB'), [toUInt32(greatest(0, JSONExtractInt(args_json, 'assetB')))], CAST([], 'Array(UInt32)')), arrayMap(item -> toUInt32(greatest(0, JSONExtractInt(item, 'assetId'))), JSONExtractArrayRaw(args_json, 'assets')))) AS asset_refs, ingested_at FROM price_data.raw_events WHERE event_name IN ('Omnipool.LiquidityAdded', 'Omnipool.LiquidityRemoved', 'Stableswap.LiquidityAdded', 'Stableswap.LiquidityRemoved', 'XYK.LiquidityAdded', 'XYK.LiquidityRemoved', 'XYK.PoolCreated', 'OmnipoolLiquidityMining.RewardClaimed', 'XYKLiquidityMining.RewardClaimed');
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.money_market_reserve_indices_mv TO price_data.money_market_reserve_indices (`pool_address` String, `reserve_address` String, `block_height` UInt32, `event_index` UInt32, `block_timestamp` DateTime, `liquidity_index` UInt256, `variable_borrow_index` UInt256, `ingested_at` DateTime) AS SELECT lower(if(pool_address = '', contract_address, pool_address)) AS pool_address, lower(ifNull(reserve_address, '')) AS reserve_address, block_height, event_index, block_timestamp, toUInt256OrZero(JSONExtractString(decoded_args_json, 'liquidityIndex')) AS liquidity_index, toUInt256OrZero(JSONExtractString(decoded_args_json, 'variableBorrowIndex')) AS variable_borrow_index, ingested_at FROM price_data.raw_money_market_reserves WHERE (event_name = 'ReserveDataUpdated') AND (ifNull(reserve_address, '') != '');
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.multisig_call_activity_mv TO price_data.multisig_call_activity (`block_height` UInt32, `extrinsic_index` Nullable(UInt32), `call_address` String, `block_timestamp` DateTime, `call_name` LowCardinality(String), `args_json` String, `ingested_at` DateTime) AS SELECT block_height, extrinsic_index, call_address, block_timestamp, call_name, args_json, ingested_at FROM price_data.raw_calls WHERE call_name IN ('Multisig.as_multi', 'Multisig.approve_as_multi', 'Multisig.as_multi_threshold_1', 'Multisig.cancel_as_multi');
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.multisig_event_activity_mv TO price_data.multisig_event_activity (`block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `block_timestamp` DateTime, `event_name` LowCardinality(String), `multisig` String, `actor` String, `call_hash` String, `ingested_at` DateTime) AS SELECT block_height, event_index, extrinsic_index, block_timestamp, event_name, JSONExtractString(args_json, 'multisig') AS multisig, multiIf(JSONHas(args_json, 'approving'), JSONExtractString(args_json, 'approving'), JSONExtractString(args_json, 'cancelling')) AS actor, JSONExtractString(args_json, 'callHash') AS call_hash, ingested_at FROM price_data.raw_events WHERE event_name IN ('Multisig.NewMultisig', 'Multisig.MultisigApproval', 'Multisig.MultisigExecuted', 'Multisig.MultisigCancelled');
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.nft_owner_latest_mv TO price_data.nft_owner_latest (`collection` String, `item` String, `owner` AggregateFunction(argMax, String, UInt64)) AS SELECT JSONExtractString(args_json, 'collection') AS collection, JSONExtractString(args_json, 'item') AS item, argMaxState(multiIf(event_name = 'Uniques.Burned', '', event_name = 'Uniques.Transferred', lower(JSONExtractString(args_json, 'to')), lower(JSONExtractString(args_json, 'owner'))), (toUInt64(block_height) * 4294967296) + event_index) AS owner FROM price_data.raw_events WHERE event_name IN ('Uniques.Issued', 'Uniques.Transferred', 'Uniques.Burned') GROUP BY collection, item;
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.ohlc_15min_mv TO price_data.ohlc_15min (`asset_id` UInt32, `interval_start` DateTime, `open_state` AggregateFunction(argMin, Decimal(38, 12), DateTime), `high_state` AggregateFunction(max, Decimal(38, 12)), `low_state` AggregateFunction(min, Decimal(38, 12)), `close_state` AggregateFunction(argMax, Decimal(38, 12), DateTime), `volume_buy_state` AggregateFunction(sum, Decimal(38, 12)), `volume_sell_state` AggregateFunction(sum, Decimal(38, 12))) AS SELECT asset_id, toStartOfInterval(block_timestamp, toIntervalMinute(15)) AS interval_start, argMinState(usd_price, block_timestamp) AS open_state, maxState(usd_price) AS high_state, minState(usd_price) AS low_state, argMaxState(usd_price, block_timestamp) AS close_state, sumState(usd_volume_buy) AS volume_buy_state, sumState(usd_volume_sell) AS volume_sell_state FROM price_data.prices WHERE block_timestamp > toDateTime(0) GROUP BY asset_id, interval_start;
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.ohlc_1d_mv TO price_data.ohlc_1d (`asset_id` UInt32, `interval_start` DateTime, `open_state` AggregateFunction(argMin, Decimal(38, 12), DateTime), `high_state` AggregateFunction(max, Decimal(38, 12)), `low_state` AggregateFunction(min, Decimal(38, 12)), `close_state` AggregateFunction(argMax, Decimal(38, 12), DateTime), `volume_buy_state` AggregateFunction(sum, Decimal(38, 12)), `volume_sell_state` AggregateFunction(sum, Decimal(38, 12))) AS SELECT asset_id, toStartOfDay(block_timestamp) AS interval_start, argMinState(usd_price, block_timestamp) AS open_state, maxState(usd_price) AS high_state, minState(usd_price) AS low_state, argMaxState(usd_price, block_timestamp) AS close_state, sumState(usd_volume_buy) AS volume_buy_state, sumState(usd_volume_sell) AS volume_sell_state FROM price_data.prices WHERE block_timestamp > toDateTime(0) GROUP BY asset_id, interval_start;
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.ohlc_1h_mv TO price_data.ohlc_1h (`asset_id` UInt32, `interval_start` DateTime, `open_state` AggregateFunction(argMin, Decimal(38, 12), DateTime), `high_state` AggregateFunction(max, Decimal(38, 12)), `low_state` AggregateFunction(min, Decimal(38, 12)), `close_state` AggregateFunction(argMax, Decimal(38, 12), DateTime), `volume_buy_state` AggregateFunction(sum, Decimal(38, 12)), `volume_sell_state` AggregateFunction(sum, Decimal(38, 12))) AS SELECT asset_id, toStartOfHour(block_timestamp) AS interval_start, argMinState(usd_price, block_timestamp) AS open_state, maxState(usd_price) AS high_state, minState(usd_price) AS low_state, argMaxState(usd_price, block_timestamp) AS close_state, sumState(usd_volume_buy) AS volume_buy_state, sumState(usd_volume_sell) AS volume_sell_state FROM price_data.prices WHERE block_timestamp > toDateTime(0) GROUP BY asset_id, interval_start;
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.ohlc_1m_mv TO price_data.ohlc_1m (`asset_id` UInt32, `interval_start` Date, `open_state` AggregateFunction(argMin, Decimal(38, 12), DateTime), `high_state` AggregateFunction(max, Decimal(38, 12)), `low_state` AggregateFunction(min, Decimal(38, 12)), `close_state` AggregateFunction(argMax, Decimal(38, 12), DateTime), `volume_buy_state` AggregateFunction(sum, Decimal(38, 12)), `volume_sell_state` AggregateFunction(sum, Decimal(38, 12))) AS SELECT asset_id, toStartOfMonth(block_timestamp) AS interval_start, argMinState(usd_price, block_timestamp) AS open_state, maxState(usd_price) AS high_state, minState(usd_price) AS low_state, argMaxState(usd_price, block_timestamp) AS close_state, sumState(usd_volume_buy) AS volume_buy_state, sumState(usd_volume_sell) AS volume_sell_state FROM price_data.prices WHERE block_timestamp > toDateTime(0) GROUP BY asset_id, interval_start;
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.ohlc_1w_mv TO price_data.ohlc_1w (`asset_id` UInt32, `interval_start` Date, `open_state` AggregateFunction(argMin, Decimal(38, 12), DateTime), `high_state` AggregateFunction(max, Decimal(38, 12)), `low_state` AggregateFunction(min, Decimal(38, 12)), `close_state` AggregateFunction(argMax, Decimal(38, 12), DateTime), `volume_buy_state` AggregateFunction(sum, Decimal(38, 12)), `volume_sell_state` AggregateFunction(sum, Decimal(38, 12))) AS SELECT asset_id, toStartOfWeek(block_timestamp, 1) AS interval_start, argMinState(usd_price, block_timestamp) AS open_state, maxState(usd_price) AS high_state, minState(usd_price) AS low_state, argMaxState(usd_price, block_timestamp) AS close_state, sumState(usd_volume_buy) AS volume_buy_state, sumState(usd_volume_sell) AS volume_sell_state FROM price_data.prices WHERE block_timestamp > toDateTime(0) GROUP BY asset_id, interval_start;
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.ohlc_30min_mv TO price_data.ohlc_30min (`asset_id` UInt32, `interval_start` DateTime, `open_state` AggregateFunction(argMin, Decimal(38, 12), DateTime), `high_state` AggregateFunction(max, Decimal(38, 12)), `low_state` AggregateFunction(min, Decimal(38, 12)), `close_state` AggregateFunction(argMax, Decimal(38, 12), DateTime), `volume_buy_state` AggregateFunction(sum, Decimal(38, 12)), `volume_sell_state` AggregateFunction(sum, Decimal(38, 12))) AS SELECT asset_id, toStartOfInterval(block_timestamp, toIntervalMinute(30)) AS interval_start, argMinState(usd_price, block_timestamp) AS open_state, maxState(usd_price) AS high_state, minState(usd_price) AS low_state, argMaxState(usd_price, block_timestamp) AS close_state, sumState(usd_volume_buy) AS volume_buy_state, sumState(usd_volume_sell) AS volume_sell_state FROM price_data.prices WHERE block_timestamp > toDateTime(0) GROUP BY asset_id, interval_start;
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.ohlc_4h_mv TO price_data.ohlc_4h (`asset_id` UInt32, `interval_start` DateTime, `open_state` AggregateFunction(argMin, Decimal(38, 12), DateTime), `high_state` AggregateFunction(max, Decimal(38, 12)), `low_state` AggregateFunction(min, Decimal(38, 12)), `close_state` AggregateFunction(argMax, Decimal(38, 12), DateTime), `volume_buy_state` AggregateFunction(sum, Decimal(38, 12)), `volume_sell_state` AggregateFunction(sum, Decimal(38, 12))) AS SELECT asset_id, toStartOfInterval(block_timestamp, toIntervalHour(4)) AS interval_start, argMinState(usd_price, block_timestamp) AS open_state, maxState(usd_price) AS high_state, minState(usd_price) AS low_state, argMaxState(usd_price, block_timestamp) AS close_state, sumState(usd_volume_buy) AS volume_buy_state, sumState(usd_volume_sell) AS volume_sell_state FROM price_data.prices WHERE block_timestamp > toDateTime(0) GROUP BY asset_id, interval_start;
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.ohlc_5min_mv TO price_data.ohlc_5min (`asset_id` UInt32, `interval_start` DateTime, `open_state` AggregateFunction(argMin, Decimal(38, 12), DateTime), `high_state` AggregateFunction(max, Decimal(38, 12)), `low_state` AggregateFunction(min, Decimal(38, 12)), `close_state` AggregateFunction(argMax, Decimal(38, 12), DateTime), `volume_buy_state` AggregateFunction(sum, Decimal(38, 12)), `volume_sell_state` AggregateFunction(sum, Decimal(38, 12))) AS SELECT asset_id, toStartOfFiveMinute(block_timestamp) AS interval_start, argMinState(usd_price, block_timestamp) AS open_state, maxState(usd_price) AS high_state, minState(usd_price) AS low_state, argMaxState(usd_price, block_timestamp) AS close_state, sumState(usd_volume_buy) AS volume_buy_state, sumState(usd_volume_sell) AS volume_sell_state FROM price_data.prices WHERE block_timestamp > toDateTime(0) GROUP BY asset_id, interval_start;
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.omnipool_pool_state_history_mv TO price_data.omnipool_pool_state_history (`asset_id` Int32, `block_height` UInt32, `block_timestamp` DateTime, `reserve_raw` String, `hub_reserve_raw` String, `shares_raw` String, `protocol_shares_raw` String, `spec_version` UInt32, `ingested_at` DateTime) AS SELECT toInt32(JSONExtractInt(a, 'asset_id')) AS asset_id, block_height, block_timestamp, JSONExtractString(a, 'reserve') AS reserve_raw, JSONExtractString(a, 'hub_reserve') AS hub_reserve_raw, JSONExtractString(a, 'shares') AS shares_raw, JSONExtractString(a, 'protocol_shares') AS protocol_shares_raw, spec_version, ingested_at FROM price_data.raw_block_snapshots ARRAY JOIN JSONExtractArrayRaw(JSONExtractRaw(payload_json, 'omnipool'), 'assets') AS a WHERE (block_height % 600) = 0;
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.omnipool_position_created_mv TO price_data.omnipool_position_created (`position_id` String, `block_height` UInt32, `ingested_at` DateTime) AS SELECT toString(JSONExtractInt(args_json, 'positionId')) AS position_id, block_height, ingested_at FROM price_data.raw_events WHERE (event_name = 'Omnipool.PositionCreated') AND (JSONExtractInt(args_json, 'positionId') > 0);
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.omnipool_position_latest_mv TO price_data.omnipool_position_latest (`position_id` String, `asset_id` AggregateFunction(argMax, Int32, UInt64), `shares` AggregateFunction(argMax, String, UInt64), `amount` AggregateFunction(argMax, String, UInt64), `price` AggregateFunction(argMax, String, UInt64)) AS SELECT JSONExtractString(args_json, 'positionId') AS position_id, argMaxState(toInt32(JSONExtractInt(args_json, 'asset')), (toUInt64(block_height) * 4294967296) + event_index) AS asset_id, argMaxState(JSONExtractString(args_json, 'shares'), (toUInt64(block_height) * 4294967296) + event_index) AS shares, argMaxState(JSONExtractString(args_json, 'amount'), (toUInt64(block_height) * 4294967296) + event_index) AS amount, argMaxState(JSONExtractString(args_json, 'price'), (toUInt64(block_height) * 4294967296) + event_index) AS price FROM price_data.raw_events WHERE event_name IN ('Omnipool.PositionCreated', 'Omnipool.PositionUpdated') GROUP BY position_id;
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.omnipool_position_state_events_mv TO price_data.omnipool_position_state_events (`position_id` String, `block_height` UInt32, `extrinsic_index` Nullable(UInt32), `event_index` UInt32, `event_kind` Enum8('created' = 1, 'updated' = 2, 'destroyed' = 3), `asset_id` Int32, `amount_raw` String, `shares_raw` String, `price_raw` String, `active` UInt8, `block_timestamp` DateTime, `ingested_at` DateTime) AS SELECT JSONExtractString(args_json, 'positionId') AS position_id, block_height, extrinsic_index, event_index, CAST(multiIf(event_name = 'Omnipool.PositionCreated', 'created', event_name = 'Omnipool.PositionUpdated', 'updated', 'destroyed'), 'Enum8(\'created\' = 1, \'updated\' = 2, \'destroyed\' = 3)') AS event_kind, if(event_name = 'Omnipool.PositionDestroyed', toInt32(0), toInt32(JSONExtractInt(args_json, 'asset'))) AS asset_id, if(event_name = 'Omnipool.PositionDestroyed', '', JSONExtractString(args_json, 'amount')) AS amount_raw, if(event_name = 'Omnipool.PositionDestroyed', '', JSONExtractString(args_json, 'shares')) AS shares_raw, if(event_name = 'Omnipool.PositionDestroyed', '', JSONExtractString(args_json, 'price')) AS price_raw, if(event_name = 'Omnipool.PositionDestroyed', toUInt8(0), toUInt8(1)) AS active, block_timestamp, ingested_at FROM price_data.raw_events WHERE event_name IN ('Omnipool.PositionCreated', 'Omnipool.PositionUpdated', 'Omnipool.PositionDestroyed');
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.otc_activity_mv TO price_data.otc_activity (`block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `block_timestamp` DateTime, `event_name` LowCardinality(String), `args_json` String, `ingested_at` DateTime) AS SELECT block_height, event_index, extrinsic_index, block_timestamp, event_name, args_json, ingested_at FROM price_data.raw_events WHERE event_name IN ('OTC.Placed', 'OTC.Cancelled', 'OTC.Filled', 'OTC.PartiallyFilled');
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.referral_claim_activity_mv TO price_data.referral_claim_activity (`block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `block_timestamp` DateTime, `event_name` LowCardinality(String), `call_address` Nullable(String), `args_json` String, `ingested_at` DateTime) AS SELECT block_height, event_index, extrinsic_index, block_timestamp, event_name, call_address, args_json, ingested_at FROM price_data.raw_events WHERE event_name = 'Referrals.Claimed';
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.staking_activity_mv TO price_data.staking_activity (`block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `block_timestamp` DateTime, `event_name` LowCardinality(String), `who` String, `args_json` String, `ingested_at` DateTime) AS SELECT block_height, event_index, extrinsic_index, block_timestamp, event_name, JSONExtractString(args_json, 'who') AS who, args_json, ingested_at FROM price_data.raw_events WHERE event_name IN ('CollatorRewards.CollatorRewarded', 'GigaHdx.Staked', 'GigaHdx.Unstaked', 'GigaHdx.UnstakeCancelled', 'GigaHdx.MigratedFromLegacy', 'GigaHdxRewards.RewardsClaimed', 'Staking.PositionCreated', 'Staking.StakeAdded', 'Staking.Unstaked', 'Staking.ForceUnstaked', 'Staking.RewardsClaimed');
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.swap_activity_mv TO price_data.swap_activity (`block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `block_timestamp` DateTime, `event_name` LowCardinality(String), `who` String, `asset_in` UInt32, `asset_out` UInt32, `amount_in` String, `amount_out` String, `ingested_at` DateTime) AS SELECT block_height, event_index, extrinsic_index, block_timestamp, event_name, JSONExtractString(args_json, 'who') AS who, toUInt32(greatest(0, JSONExtractInt(args_json, 'assetIn'))) AS asset_in, toUInt32(greatest(0, JSONExtractInt(args_json, 'assetOut'))) AS asset_out, multiIf(event_name IN ('XYK.SellExecuted', 'LBP.SellExecuted'), JSONExtractString(args_json, 'amount'), event_name IN ('XYK.BuyExecuted', 'LBP.BuyExecuted'), JSONExtractString(args_json, 'buyPrice'), JSONExtractString(args_json, 'amountIn')) AS amount_in, multiIf(event_name IN ('XYK.SellExecuted', 'LBP.SellExecuted'), JSONExtractString(args_json, 'salePrice'), event_name IN ('XYK.BuyExecuted', 'LBP.BuyExecuted'), JSONExtractString(args_json, 'amount'), JSONExtractString(args_json, 'amountOut')) AS amount_out, ingested_at FROM price_data.raw_events WHERE event_name IN ('Router.Executed', 'Router.RouteExecuted', 'Omnipool.SellExecuted', 'Omnipool.BuyExecuted', 'Stableswap.SellExecuted', 'Stableswap.BuyExecuted', 'XYK.SellExecuted', 'XYK.BuyExecuted', 'LBP.SellExecuted', 'LBP.BuyExecuted');
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.transfer_activity_by_time_mv TO price_data.transfer_activity_by_time (`block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `block_timestamp` DateTime, `event_name` LowCardinality(String), `from_account` String, `to_account` String, `amount` String, `asset_id` UInt32) AS SELECT block_height, event_index, extrinsic_index, block_timestamp, event_name, JSONExtractString(args_json, 'from') AS from_account, JSONExtractString(args_json, 'to') AS to_account, JSONExtractString(args_json, 'amount') AS amount, toUInt32(if(event_name = 'Balances.Transfer', 0, multiIf(JSONHas(args_json, 'currencyId'), JSONExtractInt(args_json, 'currencyId'), JSONHas(args_json, 'currency_id'), JSONExtractInt(args_json, 'currency_id'), JSONHas(args_json, 'assetId'), JSONExtractInt(args_json, 'assetId'), JSONHas(args_json, 'asset_id'), JSONExtractInt(args_json, 'asset_id'), 0))) AS asset_id FROM price_data.raw_events WHERE event_name IN ('Balances.Transfer', 'Tokens.Transfer', 'Currencies.Transferred');
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.transfer_activity_mv TO price_data.transfer_activity (`asset_id` UInt32, `block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `block_timestamp` DateTime, `event_name` LowCardinality(String), `from_account` String, `to_account` String, `amount` String) AS SELECT toUInt32(if(event_name = 'Balances.Transfer', 0, multiIf(JSONHas(args_json, 'currencyId'), JSONExtractInt(args_json, 'currencyId'), JSONHas(args_json, 'currency_id'), JSONExtractInt(args_json, 'currency_id'), JSONHas(args_json, 'assetId'), JSONExtractInt(args_json, 'assetId'), JSONHas(args_json, 'asset_id'), JSONExtractInt(args_json, 'asset_id'), 0))) AS asset_id, block_height, event_index, extrinsic_index, block_timestamp, event_name, JSONExtractString(args_json, 'from') AS from_account, JSONExtractString(args_json, 'to') AS to_account, JSONExtractString(args_json, 'amount') AS amount FROM price_data.raw_events WHERE event_name IN ('Balances.Transfer', 'Tokens.Transfer', 'Currencies.Transferred');
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.vote_activity_mv TO price_data.vote_activity (`block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `call_address` Nullable(String), `block_timestamp` DateTime, `event_name` LowCardinality(String), `args_json` String, `ingested_at` DateTime) AS SELECT block_height, event_index, extrinsic_index, call_address, block_timestamp, event_name, args_json, ingested_at FROM price_data.raw_events WHERE event_name IN ('ConvictionVoting.Voted', 'Democracy.Voted');
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.xcm_event_activity_mv TO price_data.xcm_event_activity (`block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `block_timestamp` DateTime, `event_name` LowCardinality(String), `asset_id` UInt32, `who` String, `amount` String, `args_json` String, `ingested_at` DateTime) AS SELECT block_height, event_index, extrinsic_index, block_timestamp, event_name, toUInt32(if((event_name IN ('Balances.Deposit', 'Balances.Issued', 'Balances.Endowed', 'Balances.Minted')), 0, multiIf(JSONHas(args_json, 'currencyId'), greatest(0, JSONExtractInt(args_json, 'currencyId')), JSONHas(args_json, 'currency_id'), greatest(0, JSONExtractInt(args_json, 'currency_id')), JSONHas(args_json, 'assetId'), greatest(0, JSONExtractInt(args_json, 'assetId')), JSONHas(args_json, 'asset_id'), greatest(0, JSONExtractInt(args_json, 'asset_id')), 0))) AS asset_id, JSONExtractString(args_json, 'who') AS who, JSONExtractString(args_json, 'amount') AS amount, args_json, ingested_at FROM price_data.raw_events WHERE event_name IN ('Currencies.Withdrawn', 'Currencies.Deposited', 'Tokens.Deposited', 'Balances.Deposit', 'Balances.Issued', 'Balances.Endowed', 'Tokens.Endowed', 'Balances.Minted', 'System.NewAccount', 'MessageQueue.Processed', 'XTokens.TransferredAssets', 'PolkadotXcm.Sent');
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.xyk_pool_registry_mv TO price_data.xyk_pool_registry (`lp_asset_id` Int32, `pool_account` String, `asset_a` Int32, `asset_b` Int32, `created_block` UInt32, `ingested_at` DateTime) AS SELECT toInt32(JSONExtractInt(args_json, 'shareToken')) AS lp_asset_id, JSONExtractString(args_json, 'pool') AS pool_account, toInt32(JSONExtractInt(args_json, 'assetA')) AS asset_a, toInt32(JSONExtractInt(args_json, 'assetB')) AS asset_b, block_height AS created_block, ingested_at FROM price_data.raw_events WHERE event_name = 'XYK.PoolCreated';
CREATE MATERIALIZED VIEW IF NOT EXISTS price_data.xyk_pool_reserve_history_mv TO price_data.xyk_pool_reserve_history (`pool_account` String, `block_height` UInt32, `block_timestamp` DateTime, `asset_a` Int32, `asset_b` Int32, `reserve_a_raw` String, `reserve_b_raw` String, `ingested_at` DateTime) AS SELECT JSONExtractString(p, 'pool_account') AS pool_account, block_height, block_timestamp, toInt32(JSONExtractInt(p, 'asset_a')) AS asset_a, toInt32(JSONExtractInt(p, 'asset_b')) AS asset_b, JSONExtractString(p, 'reserve_a') AS reserve_a_raw, JSONExtractString(p, 'reserve_b') AS reserve_b_raw, ingested_at FROM price_data.raw_block_snapshots ARRAY JOIN JSONExtractArrayRaw(JSONExtractRaw(payload_json, 'xyk'), 'pools') AS p WHERE (block_height % 600) = 0;
